#include <stdio.h>
#include <string.h>
#define MAX 1005
#define MAXN 2005
int in[MAXN], out[MAXN];
int main() {
    int T, N, M;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        char s[N][3];
        for (int i = 0; i < N; i++) scanf("%s", s[i]);
        scanf("%d", &M);
        char t[M][3];
        for (int i = 0; i < M; i++) scanf("%s", t[i]);
        // construct graph
        for (int i = 0; i < MAXN; i++) in[i] = out[i] = 0;
        for (int i = 0; i < N; i++) {
            in[s[i][1] - 'a']++;
            out[s[i][0] - 'a']++;
        }
        for (int i = 0; i < M; i++) {
            in[t[i][1] - 'a']++;
            out[t[i][0] - 'a']++;
        }
        int start = 0, end = 0;
        for (int i = 0; i < 26; i++) {
            if (in[i] > out[i]) start++;
            if (in[i] < out[i]) end++;
        }
        if (start <= 1 && end <= 1) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

